// Zonal VM (explicitly zone-pinned)
resource vm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: 'myVM-zone1'
  location: location
  zones: ['1']   // Zone-pinned: resource lives in Zone 1 only
  properties: {
    hardwareProfile: { vmSize: 'Standard_DS2_v2' }
    storageProfile: {
      imageReference: {
        publisher: 'Canonical'
        offer: 'UbuntuServer'
        sku: '22_04-lts'
        version: 'latest'
      }
    }
    // ... osProfile, networkProfile ...
  }
}

// Zone-redundant Storage Account (no zones property)
resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystorageacct'
  location: location
  // No zones property here — the sku drives zone behavior
  sku: { name: 'Standard_ZRS' }   // Zone-Redundant Storage
  kind: 'StorageV2'
}

// Zone-redundant SQL Database
resource sqlDb 'Microsoft.Sql/servers/databases@2022-05-01-preview' = {
  name: '${sqlServer.name}/mydb'
  location: location
  sku: { name: 'BC_Gen5', tier: 'BusinessCritical', capacity: 8 }
  properties: {
    zoneRedundant: true   // Platform spreads replicas across zones
  }
}
